 55→fn show_and_focus(window: &tauri::WebviewWindow) {
 56→    let position_pref = window
 57→        .app_handle()
 58→        .try_state::<Mutex<WindowConfig>>()
 59→        .and_then(|state| state.lock().ok().map(|s| s.position_pref.clone()))
 60→        .unwrap_or_else(|| "top-third".to_string());
 61→
 62→    if position_pref == "center" {
 63→        if let Err(e) = window.center() {
 64→            eprintln!("failed to center window: {e}");
 65→        }
 66→    } else {
 67→        position_near_top(window);
 68→    }
 69→
 70→    if let Err(e) = window.show() {
 71→        eprintln!("failed to show window: {e}");
 72→    }
 73→    if let Err(e) = window.set_focus() {
 74→        eprintln!("failed to focus window: {e}");
 75→    }
 76→}
