669→                        .build(),
670→                )?;
671→
672→                app.global_shortcut().register(shortcut)?;
673→
674→                let show_item =
675→                    MenuItem::with_id(app, "show", "Show Raycast", true, None::<&str>)?;
676→                let clipboard_item =
