713→                        "../icons/tray-icon@2x.png"
714→                    ))?)
715→                    .icon_as_template(true)
716→                    .tooltip("Raycast Clone")
717→                    .menu(&menu)
718→                    .show_menu_on_left_click(false)
719→                    .on_menu_event(move |app, event| match event.id().as_ref() {
720→                        "show" => {
