 84→export function RootSearchView({ onCompactChange }: RootSearchViewProps) {
 85→  const nav = useNavigation<NavViewData>();
 86→  const { push } = nav;
 87→
 88→  const [query, setQuery] = useState('');
 89→  const [filterValue, setFilterValue] = useState('all');
 90→  const [selectedIndex, setSelectedIndex] = useState(0);
 91→  const [actionsOpen, setActionsOpen] = useState(false);
 92→  const [quickLookOpen, setQuickLookOpen] = useState(false);
