 95→  const { items: hudItems, show: showHUD } = useHUD();
 96→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
 97→  const { favoriteIds, isFavorite, toggleFavorite, moveFavorite } =
 98→    useFavorites();
 99→  const { recentIds, addRecent } = useRecentCommands();
100→  const { applications, refresh: refreshApps } = useApplications();
101→
102→  useEffect(() => {
103→    if (nav.stackDepth === 0) {
104→      setQuery('');
105→      setFilterValue('all');
106→      setSelectedIndex(0);
107→      setActionsOpen(false);
108→      setQuickLookOpen(false);
109→    }
110→  }, [nav.stackDepth]);
111→
112→  useEffect(() => {
113→    if (!isTauri) return;
114→    const platform = getPlatform();
115→    let unsub: (() => void) | undefined;
116→    let cancelled = false;
117→
118→    platform.window
119→      .onFocusChanged(focused => {
120→        if (focused) refreshApps();
121→      })
122→      .then(fn => {
123→        if (cancelled) fn();
124→        else unsub = fn;
125→      });
126→
127→    return () => {
128→      cancelled = true;
129→      unsub?.();
130→    };
131→  }, [refreshApps]);
132→
133→  const appSection: SectionData | null = useMemo(() => {
134→    if (applications.length === 0) return null;
135→
136→    const items: ListItemData[] = applications.map(app => ({
137→      id: app.id,
138→      title: app.name,
139→      subtitle: 'Application',
140→      icon: app.icon ? (
141→        <img
142→          src={app.icon}
143→          alt=""
144→          width={20}
145→          height={20}
146→          style={{ borderRadius: 4 }}
147→        />
148→      ) : (
149→        <AppPlaceholderIcon />
150→      ),
151→    }));
152→
153→    return {
154→      title: 'Applications',
155→      items,
156→    };
157→  }, [applications]);
158→
159→  const registrySections = useMemo(() => getSections(), []);
160→
161→  const allSections = useMemo(() => {
162→    const sections = [...registrySections];
163→    if (!appSection) return sections;
164→
165→    const existingIdx = sections.findIndex(s => s.title === 'Applications');
166→    if (existingIdx >= 0) {
167→      const existing = sections[existingIdx]!;
168→      sections[existingIdx] = {
169→        title: existing.title,
170→        items: [
171→          ...appSection.items,
172→          ...existing.items,
173→        ],
174→      };
175→    } else {
176→      sections.push(appSection);
177→    }
178→    return sections;
179→  }, [
180→    registrySections,
181→    appSection,
182→  ]);
183→
184→  const filtered = useMemo(() => {
185→    let sections = allSections;
186→    if (filterValue === 'commands') {
187→      sections = sections.filter(
188→        s => s.title === 'Suggestions' || s.title === 'Commands',
189→      );
190→    } else if (filterValue === 'applications') {
191→      sections = sections.filter(s => s.title === 'Applications');
192→    }
193→
194→    let filteredResult: SectionData[];
195→    if (query) {
196→      const commandResults = searchCommands(query);
197→      const appItems = appSection?.items ?? [];
198→      const matchedApps = appItems
199→        .map(item => ({
200→          item,
201→          score: fuzzyScore(query, item.title)?.score ?? -Infinity,
202→        }))
203→        .filter(({ score }) => score > -Infinity)
204→        .sort((a, b) => b.score - a.score)
205→        .map(({ item }) => item);
206→
207→      const mergedSections = [...commandResults];
208→      if (matchedApps.length > 0) {
209→        const appSectionIdx = mergedSections.findIndex(
210→          s => s.title === 'Applications',
211→        );
212→        if (appSectionIdx >= 0) {
213→          const existing = mergedSections[appSectionIdx]!;
214→          const existingIds = new Set(existing.items.map(i => i.id));
215→          const newApps = matchedApps.filter(a => !existingIds.has(a.id));
216→          mergedSections[appSectionIdx] = {
217→            title: existing.title,
218→            items: [
219→              ...newApps,
220→              ...existing.items,
221→            ],
222→          };
223→        } else {
224→          mergedSections.push({
225→            title: 'Applications',
226→            items: matchedApps,
227→          });
228→        }
229→      }
230→
231→      filteredResult = mergedSections
232→        .map(s => {
233→          if (filterValue === 'commands') {
234→            return s.title === 'Suggestions' || s.title === 'Commands'
235→              ? s
236→              : {
237→                  ...s,
238→                  items: [],
239→                };
240→          }
241→          if (filterValue === 'applications') {
242→            return s.title === 'Applications'
243→              ? s
244→              : {
245→                  ...s,
246→                  items: [],
247→                };
248→          }
249→          return s;
250→        })
251→        .filter(s => s.items.length > 0);
252→    } else {
253→      filteredResult = sections;
254→    }
255→
256→    const allFlatItems = allSections.flatMap(s => s.items);
257→    const favoriteItems = favoriteIds
258→      .map(id => allFlatItems.find(item => item.id === id))
259→      .filter((item): item is ListItemData => !!item);
260→
261→    if (query) {
262→      const filteredFavs = favoriteItems.filter(
263→        item =>
264→          fuzzyMatch(query, item.title) ||
