27→let _platform: PlatformAPI | undefined;
28→let _initPromise: Promise<PlatformAPI> | undefined;
29→
30→export function getPlatform(): PlatformAPI {
31→  if (_platform) return _platform;
32→
33→  if (isTauri) {
34→    throw new Error(
35→      'Platform not initialized. Call initPlatform() before getPlatform() in Tauri mode.',
36→    );
37→  }
38→
39→  _platform = webPlatform;
40→  return _platform;
41→}
42→
43→export function initPlatform(): Promise<PlatformAPI> {
44→  if (_initPromise) return _initPromise;
45→
46→  _initPromise = (async () => {
47→    if (isTauri) {
48→      const { tauriPlatform } = await import('./tauri');
49→      _platform = tauriPlatform;
50→    } else {
51→      _platform = webPlatform;
52→    }
53→    return _platform;
54→  })();
55→
56→  return _initPromise;
57→}
